import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
import Layout_v2 from "@components/layout_v2";
import Seo from "@components/seo";
import WebDevelopmentScreen from "@screens/website-development";
import { useLocation } from "@reach/router";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const WebDevelopment = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Custom Web Development Company", link: null },
  ];
  const { data } = props;
  const fileUrl =
    data?.customWebDevImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Product",
        name: "Custom Web App Development - Justtry Technologies",
        description:
          "Justtry Technologies offers custom web app development services that help businesses create flexible and purpose-built applications aligned with their unique needs and goals.",
        url: "https://justtrytech.com/custom-web-development-company/",
        brand: {
          "@type": "Brand",
          name: "Justtry Technologies",
          logo: "https://justtrytech.com/static/b6c84c7bf987d9210bbf041b50c0fa02/e5369/custom-web-development.png",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: 4.8,
          reviewCount: 435,
        },
      },

      {
        "@type": "Organization",
        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Custom web development by Justtry Technologies provides secure, scalable, and tailored solutions to help businesses build high-performance websites and grow digitally.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce)",
          addressLocality: "Madurai",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
          addressCountry: "IN",
        },
      },

      {
        "@type": "FAQPage",
        mainEntity: [
          {
            "@type": "Question",
            name: "How much does it cost to build a bespoke web application?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Building a bespoke web application typically costs $25,000 to $150,000+, depending on complexity, features, integrations, and scalability requirements.",
            },
          },
          {
            "@type": "Question",
            name: "Can a custom web application integrate with existing business systems?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, custom web applications can seamlessly integrate with existing systems such as CRM, ERP, payment gateways, and APIs to improve efficiency and centralize operations.",
            },
          },
          {
            "@type": "Question",
            name: "How do you choose the right custom web development company?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Choose a company with proven experience, a strong portfolio, modern technology expertise, transparent communication, and reliable post-launch support.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <WebDevelopmentScreen db={db} />
    </Layout_v2>
  );
};

export default WebDevelopment;

export const queryData = graphql`
  query MyQuery {
    customWebDevImg: file(relativePath: { eq: "custom-web-development.png" }) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(filter: { slug: { eq: "custom-web-development-company" } }) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
